import React from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

const Navbar = () => {
    const { user, logout } = useAuth();
    const navigate = useNavigate();
    const location = useLocation(); // Чтобы подсвечивать активную страницу

    // --- ОБЪЕКТЫ НАВИГАЦИИ ---
    const navLinks = [
        { name: 'Главная', path: '/' },
        { name: 'Товары', path: '/products' },
        { name: 'Категории', path: '/categories' },
    ];

    // Если зашел админ, добавляем ему спец. пункты
    if (user?.role === 'admin') {
        navLinks.push({ name: 'Панель управления', path: '/admin' });
    }

    const handleLogout = () => {
        logout();
        navigate('/login');
    };

    return (
        <nav style={styles.nav}>
            <div style={styles.container}>
                <Link to="/" style={styles.logo}>🛒 Магазин</Link>

                <div style={styles.menu}>
                    {/* Рендерим кнопки из массива объектов */}
                    {navLinks.map((link) => (
                        <Link 
                            key={link.path} 
                            to={link.path} 
                            style={{
                                ...styles.link,
                                color: location.pathname === link.path ? '#007AFF' : '#666' // Подсветка активной ссылки
                            }}
                        >
                            {link.name}
                        </Link>
                    ))}

                    <div style={styles.divider}></div>

                    {user ? (
                        <div style={styles.userInfo}>
                            <span style={styles.username}>@{user.username}</span>
                            <button onClick={handleLogout} style={styles.logoutBtn}>Выйти</button>
                        </div>
                    ) : (
                        <div style={styles.authGroup}>
                            <Link to="/login" style={styles.link}>Вход</Link>
                            <Link to="/register" style={styles.registerBtn}>Регистрация</Link>
                        </div>
                    )}
                </div>
            </div>
        </nav>
    );
};

const styles = {
    nav: {
        backgroundColor: '#fff',
        padding: '12px 0',
        boxShadow: '0 2px 15px rgba(0,0,0,0.03)',
        position: 'sticky',
        top: 0,
        zIndex: 1000,
    },
    container: {
        maxWidth: '1100px',
        margin: '0 auto',
        display: 'flex',
        justifyContent: 'space-between',
        alignItems: 'center',
        padding: '0 20px',
    },
    logo: { fontSize: '22px', fontWeight: '800', color: '#1a1a1a', textDecoration: 'none' },
    menu: { display: 'flex', alignItems: 'center', gap: '25px' },
    link: { 
        textDecoration: 'none', 
        fontSize: '15px', 
        fontWeight: '600', 
        transition: '0.2s' 
    },
    divider: { width: '1px', height: '24px', backgroundColor: '#eee' },
    userInfo: { display: 'flex', alignItems: 'center', gap: '15px' },
    username: { fontSize: '14px', fontWeight: '700', color: '#333' },
    logoutBtn: {
        padding: '8px 14px',
        borderRadius: '10px',
        border: '1.5px solid #ff4d4f',
        backgroundColor: '#fff',
        color: '#ff4d4f',
        cursor: 'pointer',
        fontSize: '13px',
        fontWeight: '600',
    },
    registerBtn: {
        textDecoration: 'none',
        backgroundColor: '#007AFF',
        color: '#fff',
        padding: '10px 20px',
        borderRadius: '12px',
        fontSize: '14px',
        fontWeight: '700',
    },
    authGroup: { display: 'flex', alignItems: 'center', gap: '20px' }
};

export default Navbar;
